"use strict";parserFactory.register("gutenberg.spiegel.de",()=>new GutenbergDEParser);class GutenbergDEParser extends Parser{constructor(){super()}getChapterUrls(e){let t=e.querySelector("ul.gbnav");return Promise.resolve(util.hyperlinksToChapterList(t))}findContent(e){return e.querySelector("div#gutenb")}extractTitleImpl(e){let t=e.querySelector("h2.title");return null!=t?t.textContent.trim():e.querySelector("div.gbbreadcrumb").firstElementChild.nextElementSibling.nextElementSibling}extractAuthor(e){let t=e.querySelector("h3.author");if(null!=t)return t.textContent.trim();let r=e.querySelector("div.gbbreadcrumb").firstElementChild.nextElementSibling;return r?r.textContent.trim():super.extractAuthor(e)}}